import React, { useEffect } from "react";
import { useNavigate } from "react-router-dom";
import Navbar from "../components/Navbar";

function Landing() {
  const navigate = useNavigate();

  useEffect(() => {
    document.body.style.overflow = "hidden";
    return () => {
      document.body.style.overflow = "auto";
    };
  }, []);

  const handleContinue = () => {
    localStorage.setItem("role", "admin"); // temporary
    navigate("/login");
  };

  return (
    <>
      {/* ✅ Navbar must be inside return */}
      <Navbar variant="landing" />

      <div className="flickr-content">
        <h1 className="flickr-title animate-title">
          🧿 RetailVision AI
        </h1>

        <p className="flickr-tagline animate-tagline">
          Smarter inventory. Clearer decisions.
        </p>

        <p className="flickr-support animate-support">
          AI-powered demand forecasting, inventory optimization,
          and actionable insights for modern retail teams.
        </p>

        <button
          className="flickr-cta animate-cta"
          onClick={handleContinue}
        >
          Continue to Login
        </button>
      </div>
    </>
  );
}

export default Landing;
